- Use `@nestjs/microservices` package for Kafka integration.
- Install latest version of `kafkajs`: `npm install kafkajs`.
- Configure Kafka client in `app.module.ts`:
  ```typescript
  import { ClientsModule, Transport } from '@nestjs/microservices';

  @Module({
    imports: [
      ClientsModule.register([
        {
          name: 'KAFKA_SERVICE',
          transport: Transport.KAFKA,
          options: {
            client: {
              brokers: ['localhost:9092'],
            },
            consumer: {
              groupId: 'test-group',
            },
          },
        },
      ]),
    ],
  })
  export class AppModule {}
  ```
- Implement error handling in Kafka consumers:
  ```typescript
  import { Controller, Get } from '@nestjs/common';
  import { ClientProxy } from '@nestjs/microservices';

  @Controller('kafka')
  export class KafkaController {
    constructor(private readonly client: ClientProxy) {}

    @Get()
    async sendMessage() {
      try {
        await this.client.emit('message', 'Hello, Kafka!');
      } catch (error) {
        console.error('Error sending message:', error);
      }
    }
  }
  ```
- Configure retry logic using `kafkajs`:
  ```typescript
  import { Producer } from 'kafkajs';

  const producer = new Producer({
    clientId: 'my-producer',
    brokers: ['localhost:9092'],
    retry: {
      initialRetryTime: 100,
      retries: 5,
    },
  });

  await producer.connect();
  ```
- Implement Dead Letter Queue (DLQ) in Kafka:
  - Create a DLQ topic.
  - Configure Kafka consumer to send failed messages to the DLQ.

For more detailed information, refer to the official NestJS and Kafka documentation.

- Use `nest new project-name` to create a new NestJS project.
- Ensure you have the latest version of Node.js installed.
- Install Kafka client library using npm: `npm install @nestjs/microservices`.
- Configure Kafka in your `app.module.ts`:
  ```typescript
  import { Module } from '@nestjs/common';
  import { ClientsModule, Transport } from '@nestjs/microservices';

  @Module({
    imports: [
      ClientsModule.register([
        {
          name: 'KAFKA_SERVICE',
          transport: Transport.KAFKA,
          options: {
            clientOptions: {
              brokers: ['localhost:9092'],
            },
            consumerOptions: {
              groupId: 'test-group',
            },
          },
        },
      ]),
    ],
  })
  export class AppModule {}
  ```
- Implement custom exception handling in your Kafka service:
  ```typescript
  import { Controller, Get } from '@nestjs/common';
  import { ClientProxy, MessagePattern } from '@nestjs/microservices';

  @Controller('kafka')
  export class KafkaController {
    constructor(private readonly client: ClientProxy) {}

    @MessagePattern({ cmd: 'test' })
    async test() {
      try {
        return await this.client.send({ cmd: 'test' }, {}).toPromise();
      } catch (error) {
        // Handle error
        console.error('Kafka error:', error);
        throw new Error('Failed to process message');
      }
    }
  }
  ```
- Ensure your Kafka server is running and accessible at `localhost:9092`.
- Use `npm run start` to run your NestJS application.
